{
    public void Play(MediaPlayer p)  { Console.WriteLine("Starting playback..."); p.SetState(new PlayingState()); }
    public void Pause(MediaPlayer p) => Console.WriteLine("Nothing is playing.");
    public void Stop(MediaPlayer p)  => Console.WriteLine("Already stopped.");
    public override string ToString() => "IdleState";
}

class PlayingState : IPlayerState
{
    public void Play(MediaPlayer p)  => Console.WriteLine("Already playing.");
    public void Pause(MediaPlayer p) { Console.WriteLine("Pausing...");   p.SetState(new PausedState()); }
    public void Stop(MediaPlayer p)  { Console.WriteLine("Stopping..."); p.SetState(new IdleState()); }
    public override string ToString() => "PlayingState";
}

class PausedState : IPlayerState
{
    public void Play(MediaPlayer p)  { Console.WriteLine("Resuming..."); p.SetState(new PlayingState()); }
    public void Pause(MediaPlayer p) => Console.WriteLine("Already paused.");
    public void Stop(MediaPlayer p)  { Console.WriteLine("Stopping..."); p.SetState(new IdleState()); }
    public override string ToString() => "PausedState";
}

// Context
class MediaPlayer
{
    private IPlayerState _state = new IdleState();

    public void SetState(IPlayerState s) => _state = s;
    public string GetState()             => _state.ToString()!;

    public void Play()  => _state.Play(this);
    public void Pause() => _state.Pause(this);
    public void Stop()  => _state.Stop(this);
