from __future__ import annotations
from abc import ABC, abstractmethod


class PlayerState(ABC):
    @abstractmethod
    def play(self, player: MediaPlayer) -> None: ...
    @abstractmethod
    def pause(self, player: MediaPlayer) -> None: ...
    @abstractmethod
    def stop(self, player: MediaPlayer) -> None: ...


class IdleState(PlayerState):
    def play(self, player: MediaPlayer) -> None:
        print('Starting playback...')
        player.set_state(PlayingState())
    def pause(self, player: MediaPlayer) -> None:
        print('Nothing is playing.')
    def stop(self, player: MediaPlayer) -> None:
        print('Already stopped.')


class PlayingState(PlayerState):
    def play(self, player: MediaPlayer) -> None:
        print('Already playing.')
    def pause(self, player: MediaPlayer) -> None:
        print('Pausing...')
        player.set_state(PausedState())
    def stop(self, player: MediaPlayer) -> None:
        print('Stopping...')
        player.set_state(IdleState())


class PausedState(PlayerState):
    def play(self, player: MediaPlayer) -> None:
        print('Resuming...')
        player.set_state(PlayingState())
    def pause(self, player: MediaPlayer) -> None:
        print('Already paused.')
    def stop(self, player: MediaPlayer) -> None:
        print('Stopping...')
        player.set_state(IdleState())


# Context
class MediaPlayer:
    def __init__(self) -> None:
        self._state: PlayerState = IdleState()

    def set_state(self, state: PlayerState) -> None:
        self._state = state

    def get_state(self) -> str:
        return type(self._state).__name__

    def play(self)  -> None: self._state.play(self)
    def pause(self) -> None: self._state.pause(self)
    def stop(self)  -> None: self._state.stop(self)


# Usage
player = MediaPlayer()

player.play()                   # Starting playback...
player.pause()                  # Pausing...
player.play()                   # Resuming...
player.stop()                   # Stopping...

print(player.get_state())       # IdleState
